def solve():
    str = input().strip()
    str = str.capitalize()
    result = ''
    for i in range(len(str)):
        if str[i] == ' ':
            result += ' '
        elif i == 0 or str[i-1] == ' ':
            result += str[i].upper()
        else:
            result += str[i].lower()
    print(result)

